parameters.text:
Generate a full industrial report of the AI software factory execution.

The report must summarize all stages and provide a final delivery status.

Return ONLY valid JSON with this structure:

{
  "wf07_industrial_report": {
    "summary": {
      "project": "",
      "work_item_id": "",
      "title": "",
      "event_type": ""
    },
    "pipeline_overview": {
      "requirement_analysis": "completed | blocked",
      "technical_breakdown": "completed | blocked",
      "code_assistance": "completed | blocked",
      "qa_tests": "completed | blocked",
      "repository_update": "completed | blocked",
      "ci_cd": "success | failed | blocked",
      "ai_review": "approved | warning | rejected"
    },
    "key_outputs": {
      "files_generated": [],
      "tests_generated": [],
      "commands_executed": []
    },
    "issues_detected": [],
    "final_status": "ready | needs_changes | blocked",
    "delivery_readiness": true,
    "recommendation": "deliver | improve | stop",
    "traceability": {
      "has_requirement": true,
      "has_tests": true,
      "has_ci_cd": true,
      "has_review": true
    }
  }
}

Report context:
{{$json.report_context}}

parameters.jsCode:
const originalInput = $('Set - Prepare Report Context').item.json;
const current = $input.item.json;

let aiOutput =
  current.output ||
  current.text ||
  current.message ||
  current.content ||
  current.data ||
  current;

if (typeof aiOutput === 'string') {
  aiOutput = aiOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    aiOutput = JSON.parse(aiOutput);
  } catch (error) {
    aiOutput = {
      wf07_industrial_report: {
        summary: {
          project: originalInput.project || '',
          work_item_id: originalInput.work_item_id || '',
          title: originalInput.title || '',
          event_type: originalInput.event_type || ''
        },
        pipeline_overview: {},
        key_outputs: {},
        issues_detected: ["Invalid JSON generated by reporter"],
        final_status: "blocked",
        delivery_readiness: false,
        recommendation: "stop",
        traceability: {
          has_requirement: false,
          has_tests: false,
          has_ci_cd: false,
          has_review: false
        }
      }
    };
  }
}

return {
  json: {
    ...originalInput,
    wf07_industrial_report: aiOutput.wf07_industrial_report || aiOutput,
    wf07_status: "completed"
  }
};
